effect.shader:
vec2 l2s( vec2 v ) {
    return (vec4(v,0.,1.)*acLayerToScreen).xy;
}

mat2 rot2d(float a) {
    float c = cos(a);
    float s = sin(a);
    return mat2( c, -s, s, c );
}

const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

vec2 perpCCW(vec2 v) {
    return vec2(v.y,-v.x);
}

vec2 perpCW(vec2 v) {
    return vec2(-v.y,v.x);
}

vec4 composite( vec4 a, vec4 b) {
    return a * (1. - b.a) + b;
}

vec4 premult( vec4 c ) {
    return vec4(c.rgb * c.a, c.a);
}

void main() {

    vec2 st = acLayerNorm;

    float a = (angle+180.0) * 0.0174532925;
    float la = (lightAngle) * 0.0174532925;
    vec2 lightVec = vec2(1.,0.) * rot2d(la);
    float band = 1. / amount;

    st -= 0.5;
    st *= rot2d(a);
    st += 0.5;

    st.y += (phase + 0.055) / 10. + 0.5/acLayerSize.y;

    vec4 result = vec4(0.);

    float pixel = 1./min(acLayerSize.x, acLayerSize.y);
    float soffs = pixel * 4.0 * max(1.0,width);
    float bandPixel = pixel/amount/width;
    float baseThickness = thickness / width * amount / 20.;

    for( float i=-1.0; i<width+1.0; i += 1.0 ) {

        vec2 uv = st;

        float bandId = floor(uv.y / band) + i;
        float py = mod(uv.y,band);
        uv.y -= py;
        uv.y += band * i;
        py /= band;

        uv.y -= (phase + 0.055) / 10. + 0.5/acLayerSize.y;
        uv -= 0.5;
        uv *= rot2d(-a);
        uv += 0.5;

        py = 1.-((1.-py) + i)/width;

        vec4 texColor = texture2DCv(inputImg.texture,l2s(uv));
        vec4 texColorL = texture2DCv(blurBuf.texture,l2s(uv+vec2(-soffs,0.)));
        vec4 texColorR = texture2DCv(blurBuf.texture,l2s(uv+vec2(soffs,0.)));
        float luminance = heightSource==0 ? texColor.a : dot(texColor.rgb, luminanceWeighting);
        float lumL = heightSource==0 ? texColorL.a : dot(texColorL.rgb, luminanceWeighting);
        float lumR = heightSource==0 ? texColorR.a : dot(texColorR.rgb, luminanceWeighting);
        if( !invert ) {
            lumL = 1. - lumL;
            lumR = 1. - lumR;
            luminance = 1. - luminance;
        }

        vec2 aa = vec2(-soffs, lumL*band*width);
        vec2 cc = vec2(soffs, lumR*band*width);
        vec2 n = normalize(perpCCW(cc-aa));

        vec2 dac = cc-aa;
        float slope = abs(dac.y) / abs(dac.x);

        float th = baseThickness * (1.+slope*0.5);

        float line = smoothstep(luminance-th-bandPixel,luminance-th,py) * smoothstep(luminance+th+bandPixel,luminance+th,py);

        vec2 vn = n*0.5 + 0.5;
        vec4 lc = saturate(mix(lineColor,composite(lineColor,premult(lightColor)),saturate(dot(n,lightVec))) * saturate(line));

        float p = smoothstep(luminance-0.02,luminance+0.01,py);

        vec4 c = texColor * p;
        if(heightSource == 0) {
            c = mix(composite(texColor,premult(color1)), composite(texColor,premult(color2)), py) * p;
        } else {
            c = mix(premult(color1), premult(color2), py) * p;
        }
        if(maskToLayer) {
            c *= texColor.a;
            lc *= texColor.a;
        }
        result = result * (1.-c.a) + c;
        result = result * (1.-lc.a) + lc;
    }


    gl_FragColor = result;
}
